package com.jc.backend.verification;
import static org.assertj.core.api.Assertions.assertThat;import java.nio.file.*;import java.util.List;import org.junit.jupiter.api.*;
@Tag("p2-verification") class P2RecommendationStaticTest {@Test void baselineScriptsStayExact() throws Exception{Path p1=RepositoryLayout.resolve("database/journey-connect-db-v2.6"),p2=RepositoryLayout.resolve("database/journey-connect-db-v2.7"),canonical=RepositoryLayout.resolve("jc-backend/src/test/resources/db/canonical");for(int i=1;i<=24;i++){String prefix=String.format("%02d_",i);Path src;try(var stream=Files.list(p1)){src=stream.filter(x->x.getFileName().toString().startsWith(prefix)).findFirst().orElseThrow();}StaticContractSupport.assertExactCopy(src,p2.resolve(src.getFileName()),"P0/P1 baseline");StaticContractSupport.assertExactCopy(src,canonical.resolve(src.getFileName()),"canonical baseline");}for(String s:List.of("25_recommendation_p2_evaluation_release.sql","26_recommendation_p2_evaluation_release_smoke_test.sql"))StaticContractSupport.assertExactCopy(p2.resolve(s),canonical.resolve(s),"P2 canonical");}
@Test void coreIsPureAndVersioned() throws Exception{Path dir=RepositoryLayout.resolve("jc-recommendation-core/src/main/java/com/jc/recommendation/p2");for(Path p:Files.walk(dir).filter(Files::isRegularFile).toList()){String s=Files.readString(p);for(String token:List.of("org.springframework","jakarta.persistence","JdbcTemplate","EntityManager","Instant.now()","Math.random","new Random(","SecureRandom"))assertThat(s).as(RepositoryLayout.relative(p)).doesNotContain(token);}assertThat(RepositoryLayout.read("jc-recommendation-core/src/main/java/com/jc/recommendation/p2/P2Policies.java")).contains("recommendation-metrics-v1","recommendation-evaluation-policy-v1","engagement_rate","fallback_rate");assertThat(RepositoryLayout.read("jc-recommendation-core/src/main/java/com/jc/recommendation/p2/P2EvaluationEngine.java")).contains("bootstrap","applyHolm","support","rollbackRegressionThreshold");}
@Test void runtimePreservesDefaultAndBindsVariants() throws Exception{String runtime=RepositoryLayout.read("jc-backend/src/main/java/com/jc/backend/recommendation/application/RecommendationP1RuntimeService.java");String props=RepositoryLayout.read("jc-backend/src/main/java/com/jc/backend/recommendation/config/RecommendationP2Properties.java");String source=RepositoryLayout.read("jc-backend/src/main/java/com/jc/backend/recommendation/p2/RecommendationP2ObservationSource.java");assertThat(runtime).contains("if (!p2AssignmentService.isEnabled())","shouldServeCanary(userId)","assignment.variant() == Variant.BASELINE","recordExposure");assertThat(props).contains("private boolean assignmentEnabled","private int treatmentAllocationBasisPoints");assertThat(source).contains("interval '7 days'","engagement_rate","fallback_rate");}
@Test void schemaIsAppendOnlyAndEvidenceComplete() throws Exception{String sql=RepositoryLayout.read("database/journey-connect-db-v2.7/25_recommendation_p2_evaluation_release.sql");assertThat(sql).contains("recommendation_p2_experiment_assignment","recommendation_p2_experiment_exposure","recommendation_p2_dataset_snapshot","recommendation_p2_metric_definition","recommendation_p2_evaluation_run","recommendation_p2_metric_result","recommendation_p2_gate_result","recommendation_p2_release_decision","validate_recommendation_p2_exposure_binding","recommendation_p1_policy_assignment","validate_recommendation_p2_release_decision","gate_count = 5","pass_count = 5","gate_a_contract_integrity","gate_e_operational_approval","append_only");assertThat(sql.toLowerCase()).contains("revoke update,delete,truncate");}
@Test void tasksAndScriptsRegistered() throws Exception{assertThat(RepositoryLayout.read("jc-backend/build.gradle.kts")).contains("p2ContractVerification","p2EvaluationIntegration","p2Verification");assertThat(RepositoryLayout.read("jc-recommendation-core/build.gradle.kts")).contains("p2CoreContractTest");assertThat(RepositoryLayout.read("jc-backend/src/test/java/com/jc/backend/CanonicalPostgresInitializer.java")).contains("25_recommendation_p2_evaluation_release.sql","26_recommendation_p2_evaluation_release_smoke_test.sql");}}
